#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int *stack = (int*)malloc(N * sizeof(int));
        int top = -1;
        for (int i = 0; i < N; ++i) {
            while (top >= 0 && stack[top] >= a[i]) top--;
            if (top == -1) printf("-1");
            else printf("%d", stack[top]);
            if (i != N-1) printf(" ");
            stack[++top] = a[i];
        }
        printf("\n");
        free(a);
        free(stack);
    }
    return 0;
}

